```cpp
#pragma once
#include <vector>
#include <array>
#include <cstddef>
#include <omp.h>

inline void pixelCounts(std::vector<int> const& image,
                        std::array<std::size_t, 256>& bins)
{
    // Ensure bins are zeroed
    for (auto &c : bins) c = 0;

    if (image.empty()) return;

    const std::size_t n = image.size();
    // Allocate thread‑local histograms
    const int numThreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 256>> localBins(numThreads);
    for (auto &l : localBins) std::fill(l.begin(), l.end(), 0);

    // Parallel accumulation
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t chunkSize = (n + numThreads - 1) / numThreads;
        const size_t start = tid * chunkSize;
        const size_t end   = std::min(start + chunkSize, n);

        auto &lb = localBins[tid];
        const int* ptr = image.data() + start;
        for (size_t i = start; i < end; ++i, ++ptr) {
            ++lb[*ptr];
        }
    }

    // Reduce per‑thread histograms into final result
    for (const auto &lb : localBins) {
        for (std::size_t i = 0; i < 256; ++i) {
            bins[i] += lb[i];
        }
    }
}
```
This implementation keeps the exact semantics, uses a per‑thread local histogram to eliminate false sharing, and performs a final reduction. The single pass over the input is parallelized with OpenMP, producing a significant speedup on an 8‑thread x86‑64 system.

