/// Count the number of ones in an NxN adjacency matrix.
/// The matrix is stored in row‑major order.
///
/// @tparam IntType the integer type used in the matrix (here int).
/// @param A      the adjacency matrix in row‑major order.
/// @param N      the dimension of the matrix (number of rows/columns).
/// @return       the exact count of edges (number of 1s) in the matrix.
///
/// This implementation is fully equivalent to the reference but uses
/// pointer arithmetic and OpenMP to exploit parallelism on modern
/// multi‑core CPUs. The outer loop is collapsed with the inner loop
/// for better load‑balance, and a reduction clause safely aggregates
/// the count from all threads. No other behaviour changes are made.
int edgeCount(const std::vector<int>& A, std::size_t N) {
    // Fast path for empty matrices
    if (N == 0 || A.empty()) return 0;

    const int* data = A.data();          // Raw pointer to matrix data
    std::size_t total = N * N;           // Total number of elements

    int count = 0;                       // Accumulator for the result

    #pragma omp parallel for reduction(+:count) schedule(static)
    for (std::size_t idx = 0; idx < total; ++idx) {
        // Count only the 1‑valued edges
        count += (data[idx] == 1) ? 1 : 0;
    }

    return count;
}
