#pragma once
#include <cstddef>
#include <vector>
#include <algorithm>
#include <omp.h>

/* Compute the highest node degree in the undirected graph.
 * The graph is defined in the adjacency matrix A.
 * A is an NxN adjacency matrix stored in row-major order.
 * The matrix is symmetric and contains 0/1 entries.
 * Returns the maximum degree of any node.
 */
int maxDegree(std::vector<int> const& A, size_t N) {
    int highestDegree = 0;

    /* Parallel over rows: each thread computes the maximum degree it sees
     * and we reduce to the global maximum. */
#pragma omp parallel for reduction(max : highestDegree)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        /* Count ones in row i */
        int degree = 0;
        const int *row = &A[i * N];

        /* SIMD-friendly loop: process 8 ints at a time */
        int j = 0;
#if defined(__clang__) || defined(__GNUC__) || defined(__INTEL_COMPILER)
        /* Clang/GCC/ICC can auto-vectorize the following loop. */
        for (; j + 7 < static_cast<int>(N); j += 8) {
            degree += row[j] + row[j+1] + row[j+2] + row[j+3]
                    + row[j+4] + row[j+5] + row[j+6] + row[j+7];
        }
#endif
        /* Handle remaining elements */
        for (; j < static_cast<int>(N); ++j) {
            degree += row[j];
        }

        if (degree > highestDegree) highestDegree = degree;
    }

    return highestDegree;
}
