```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <utility>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Efficient sparse × sparse → dense multiplication.
 * Y is dense MxN with row‑major layout.
 * The routine keeps the exact behaviour of the original
 * double nested loop but exploits hashing and OpenMP parallelism.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N) {
    // Initialise dense result
    Y.assign(M * N, 0.0);

    // Build a map from X.row -> list of (col,value)
    // This replacement removes the inner loop over all X.
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> xMap;
    xMap.reserve(X.size() * 2); // avoid rehashes
    for (auto const& xx : X) {
        xMap[xx.row].emplace_back(xx.column, xx.value);
    }

    // Parallel over non‑zero entries of A
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        auto const& a = A[i];
        auto it = xMap.find(a.column);
        if (it == xMap.end()) continue;        // no matching row in X
        size_t row = a.row * N;                // base index for this row in Y
        double mult = a.value;
        for (auto const& xy : it->second) {
            Y[row + xy.first] += mult * xy.second;
        }
    }
}
