#pragma once
#include <vector>
#include <complex>
#include <cmath>
#ifdef _OPENMP
#  include <omp.h>
#endif

#ifndef M_PI
#  define M_PI 3.14159265358979323846
#endif

//------------------------------------------------------------------------------
// Fast, thread‑safe, deterministic DFT implementation (O(N²) time)
//------------------------------------------------------------------------------
void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    const double two_pi_over_N = 2.0 * M_PI / static_cast<double>(N);

    // Parallelise the outer loop – each output index is independent.
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        double real_sum = 0.0;
        double imag_sum = 0.0;

        for (std::size_t n = 0; n < N; ++n) {
            const double angle = static_cast<double>(n) * static_cast<double>(k) * two_pi_over_N;
            const double cos_val = std::cos(angle);
            const double sin_val = std::sin(angle);

            const double xn = x[n];
            real_sum += xn * cos_val;
            imag_sum -= xn * sin_val;   // note the negative sign
        }
        output[k] = std::complex<double>(real_sum, imag_sum);
    }
}
