```cpp
#pragma once
#include <vector>

struct Element {
    std::size_t index;
    double value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the dense vector z.
 * Both x and y must be sorted by `index`.
 */
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double>& z)
{
    std::size_t xi = 0, yi = 0;
    const std::size_t xn = x.size(), yn = y.size();

    // Merge the two sorted lists.
    while (xi < xn && yi < yn) {
        const std::size_t ix = x[xi].index;
        const std::size_t jy = y[yi].index;

        if (ix < jy) {
            z[ix] += alpha * x[xi].value;
            ++xi;
        } else if (ix > jy) {
            z[jy] += y[yi].value;
            ++yi;
        } else {
            z[ix] += alpha * x[xi].value + y[yi].value;
            ++xi;
            ++yi;
        }
    }

    // Process remaining elements.
    while (xi < xn) {
        const std::size_t ix = x[xi].index;
        z[ix] += alpha * x[xi].value;
        ++xi;
    }
    while (yi < yn) {
        const std::size_t jy = y[yi].index;
        z[jy] += y[yi].value;
        ++yi;
    }
}
