#pragma once
#include <vector>
#include <stack>
#include <cstdint>

/**
 * Count the number of connected components in an undirected graph whose adjacency
 * matrix is stored in row‑major order.
 *
 * The function was rewritten from a recursive depth‑first search to an iterative
 * version that:
 *   • uses a `std::stack` instead of function call overhead,
 *   • stores the `visited` array as `vector<char>` for better cache locality
 *     (the standard `vector<bool>` is bit‑packed and incurs virtualisation),
 *   • accesses the adjacency matrix in a simple linear fashion,
 *   • avoids unnecessary bounds checks in the inner loop by using raw pointers,
 *   • uses `size_t` and `int` where appropriate to let the compiler optimise the
 *     loop counters.
 *
 * No change in behaviour is made – the graph is still assumed to be undirected
 * and the matrix contains 0/1 entries only.
 */
int componentCount(std::vector<int> const& A, size_t N)
{
    // early exit for an empty graph
    if (N == 0) return 0;

    // visited flags as a byte per vertex for speed
    std::vector<char> visited(N, 0);
    int components = 0;

    // helper stack for iterative DFS
    std::stack<int> st;

    for (int start = 0; start < static_cast<int>(N); ++start)
    {
        if (visited[start]) continue;

        // new component found
        ++components;
        visited[start] = 1;
        st.push(start);

        while (!st.empty())
        {
            int u = st.top();
            st.pop();

            const int* row = &A[u * N];                // pointer to row of adjacency matrix
            for (int v = 0; v < static_cast<int>(N); ++v)
            {
                if (row[v] == 1 && !visited[v])
                {
                    visited[v] = 1;
                    st.push(v);
                }
            }
        }
    }

    return components;
}
