#pragma once
#include <vector>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/*
 * Compute y = alpha*A*x + beta*y
 * with A in COO format.
 * x and y are vectors of length N, A is M x N.
 *
 * Parameters
 * -----------
 * alpha: scalar multiplier for A*x
 * A:    sparse matrix in COO format
 * x:    input vector
 * beta: scalar multiplier for old y
 * y:    input/output vector (modified in place)
 * M:    number of rows of A
 * N:    number of columns of A
 */
void spmv(double alpha,
          std::vector<COOElement> const& A,
          std::vector<double> const& x,
          double beta,
          std::vector<double> &y,
          size_t M, size_t N)
{
    // Scale y by beta in parallel
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    // Add alpha*A*x to y in parallel
    // Each element of A can contribute to the same row; use atomic update
    #pragma omp parallel for schedule(static)
    for (size_t k = 0; k < A.size(); ++k) {
        const COOElement& e = A[k];
        if (e.row < M && e.column < N) {
            double contrib = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += contrib;
        }
    }
}
