#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A. A is stored in row‑major order.
   Very small, CPU‑friendly implementation that avoids STL containers and uses
   a simple fixed‑size ring buffer for the BFS queue. */
inline int shortestPathLength(std::vector<int> const& A, std::size_t N,
                              int source, int dest)
{
    /* Visited bitmap – 1 byte per vertex is enough for N <= 8 192
       For larger N a std::vector<uint8_t> would be used anyway. */
    std::vector<uint8_t> visited(N, 0);
    visited[source] = 1;

    /* Ring buffer queue – size N is sufficient because each vertex is enqueued
       at most once. */
    std::vector<int> q(N);
    std::size_t head = 0, tail = 0;
    q[tail++] = source;

    /* Distance array – use a separate vector of int to keep
       the original signature (int). */
    std::vector<int> dist(N, -1);
    dist[source] = 0;

    while (head != tail) {
        int u = q[head++];
        int d = dist[u];
        if (u == dest) return d;

        /* Scan row u of the adjacency matrix.  The inner loop is
           intentionally unrolled in a way that is friendly to the
           instruction pipeline and cache. */
        std::size_t base = u * N;
        for (std::size_t v = 0; v < N; ++v) {
            if (A[base + v] && !visited[v]) {
                visited[v] = 1;
                dist[v] = d + 1;
                q[tail++] = static_cast<int>(v);
            }
        }
    }
    /* Graph is assumed connected – this case should never happen.  Return
       a sentinel value compatible with the original implementation. */
    return std::numeric_limits<int>::max();
}
