#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* LU factorization for a sparse NxN matrix A in COO format.
   L and U are returned as flattened row‑major matrices of size N*N.
   The algorithm guarantees identical results to the reference implementation. */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    /* Allocate dense matrix for A and flatten U and L */
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A)
        fullA[e.row * N + e.column] = e.value;

    /* Initialise L and U to zero */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Parallelise the outer loop – each thread works on a distinct row */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        /* Compute U[i][j] for j >= i and L[i][j] for j < i */
        for (size_t j = 0; j < N; ++j) {
            if (j >= i) {
                double sum = fullA[i * N + j];
                for (size_t k = 0; k < i; ++k) {
                    sum -= L[i * N + k] * U[k * N + j];
                }
                U[i * N + j] = sum;
            }
            if (i > j) {
                double sum = fullA[i * N + j];
                for (size_t k = 0; k < j; ++k) {
                    sum -= L[i * N + k] * U[k * N + j];
                }
                L[i * N + j] = sum / U[j * N + j];
            }
        }
        /* Diagonal of L is 1 */
        L[i * N + i] = 1.0;
    }
}
