#pragma once
#include <vector>
#include <algorithm>
#include <numeric>
#include <cstddef>
#include <omp.h>

/* Union–Find (Disjoint Set Union) data structure */
class DSU {
public:
    explicit DSU(std::size_t n)
        : parent(n), sz(n, 1) {
        std::iota(parent.begin(), parent.end(), 0);
    }

    // Find with path compression
    std::size_t find(std::size_t x) const {
        std::size_t p = parent[x];
        while (p != parent[p]) {
            p = parent[p];
        }
        // Path compression
        std::size_t cur = x;
        while (cur != parent[cur]) {
            std::size_t next = parent[cur];
            parent[cur] = p;
            cur = next;
        }
        return p;
    }

    // Union by size
    void unite(std::size_t a, std::size_t b) {
        a = find(a);
        b = find(b);
        if (a == b) return;
        if (sz[a] < sz[b]) std::swap(a, b);
        parent[b] = a;
        sz[a] += sz[b];
    }

    const std::vector<std::size_t>& getSizes() const { return sz; }

private:
    std::vector<std::size_t> parent;
    mutable std::vector<std::size_t> sz;   // mutable because find modifies parent
};

/* Return the number of vertices in the largest component of the graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major. */
int largestComponent(std::vector<int> const& A, std::size_t N) {
    DSU dsu(N);

    // Parallel iterate over upper triangle (i < j) of the matrix
    #pragma omp parallel for schedule(guided)
    for (std::ptrdiff_t idx = 0; idx < static_cast<std::ptrdiff_t>(N) * N; ++idx) {
        std::size_t i = static_cast<std::size_t>(idx / N);
        std::size_t j = static_cast<std::size_t>(idx % N);
        if (i < j && A[idx] == 1) {
            dsu.unite(i, j);
        }
    }

    // Find the largest component size
    int max_size = 0;
    const auto& sizes = dsu.getSizes();
    for (std::size_t i = 0; i < N; ++i) {
        if (dsu.find(i) == i) {          // root of a component
            max_size = std::max(max_size, static_cast<int>(sizes[i]));
        }
    }
    return max_size;
}
