/* Return the area of the smallest triangle that can be formed by any 3 points.
   Preserves the exact behaviour of the original function.
   The implementation is parallelised using OpenMP and avoids
   unnecessary temporaries for improved speed.
*/
double smallestArea(const std::vector<Point>& points)
{
    const size_t n = points.size();
    if (n < 3) return 0.0;

    const double INF = std::numeric_limits<double>::max();
    double globalMin = INF;

    // Parallel over outer loop, each thread keeps its own local minimum.
    #pragma omp parallel
    {
        double localMin = INF;
        #pragma omp for schedule(dynamic, 64) nowait
        for (size_t i = 0; i + 2 < n; ++i)
        {
            const Point& pi = points[i];
            for (size_t j = i + 1; j + 1 < n; ++j)
            {
                const Point& pj = points[j];
                for (size_t k = j + 1; k < n; ++k)
                {
                    const double area = triArea(pi, pj, points[k]);
                    if (area < localMin) localMin = area;
                }
            }
        }
        // Update global minimum safely
        #pragma omp critical
        if (localMin < globalMin) globalMin = localMin;
    }

    return globalMin;
}
