#include <omp.h>

/*
 * Set every cell's value to 1 if it has exactly one neighbor that's a 1.
 * Otherwise set it to 0.
 *
 * input and output are NxN grids of ints stored in row‑major order.
 */
static inline void cellsXOR(std::vector<int> const& input,
                            std::vector<int> &output,
                            size_t N)
{
    int*  out = output.data();
    int const* in = input.data();

    /* Parallelise the two nested loops.  The collapse(2) pragma lets
     * OpenMP treat the i‑j pair as a single 2‑D loop range.  The loop
     * body is cache friendly because it accesses the input array
     * in row‑major order (the most locality‑friendly direction).
     */
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        size_t base   = i * N;           // row offset
        size_t row_p1 = base + N;        // i+1 row offset (if exists)
        size_t row_m1 = (i ? base - N : 0);  // i-1 row offset (if exists)

        for (size_t j = 0; j < N; ++j)
        {
            int count = 0;

            /* above */
            if (i && in[row_m1 + j] == 1) ++count;
            /* below */
            if (i + 1 < N && in[row_p1 + j] == 1) ++count;
            /* left */
            if (j && in[base + j - 1] == 1) ++count;
            /* right */
            if (j + 1 < N && in[base + j + 1] == 1) ++count;

            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
