static inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // ---- 1. Bit‑reversal permutation -------------------------------------------------
    const unsigned int logN = static_cast<unsigned int>(std::log2(N));
    std::vector<std::complex<double>> rev(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = _byteswap_ulong(j);           // reverse 32‑bit word
        j >>= (32 - logN);                // keep only logN bits
        rev[j] = x[i];
    }
    x.swap(rev);

    // ---- 2. Iterative Cooley–Tukey (radix‑2) -----------------------------------------
    // Pre‑compute twiddle factors for maximum stage
    std::vector<std::complex<double>> twiddles(N / 2);
    const double PI = std::acos(-1.0);
    for (std::size_t k = 0; k < N / 2; ++k) {
        double angle = -2.0 * PI * k / static_cast<double>(N);
        twiddles[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    for (std::size_t step = 1; step < N; step <<= 1) {
        const std::size_t halfstep = step;
        const std::size_t twiddle_step = N / (step << 1);

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += (step << 1)) {
            for (std::size_t j = 0; j < halfstep; ++j) {
                const std::size_t idx = i + j;
                const std::size_t idx_t = idx + halfstep;

                const auto t = x[idx_t] * twiddles[j * twiddle_step];
                const auto u = x[idx];

                x[idx]      = u + t;
                x[idx_t]    = u - t;
            }
        }
    }

    // ---- 3. Conjugate every element --------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        x[i] = std::conj(x[i]);
    }
}
