#pragma once
#include <vector>
#include <cstddef>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
   std::size_t row, column;
   double value;
};

/*
 * Solve the sparse linear system Ax = b for x.
 * A is a sparse NxN matrix in COO format.
 * b and x are dense vectors with N elements.
 * The function preserves the exact semantics of the reference implementation,
 * but it is heavily optimised for a modern x86‑64 CPU with 8 hardware threads.
 *
 * Note: The algorithm is still Gaussian elimination with partial
 * pivoting (O(N³)).  The matrix is stored in a contiguous 1‑D array for
 * data locality and the only explicit parallel region is in the
 * inner row elimination step, which does not affect the result.
 */
void solveLinearSystem(const std::vector<COOElement>& A,
                       const std::vector<double>& b,
                       std::vector<double>& x,
                       std::size_t N)
{
   /* 1. Build a dense matrix in row‑major order.
    *    Allocating a single contiguous block gives the compiler
    *    better optimisation opportunities and reduces cache misses. */
   std::vector<double> matrix(N * N, 0.0);
   for (const auto& el : A)
       matrix[el.row * N + el.column] = el.value;

   /* 2. Copy and initialise RHS vector */
   std::vector<double> rhs = b;
   x.assign(N, 0.0);

   /* 3. Gaussian elimination with partial pivoting */
   for (std::size_t i = 0; i < N; ++i)
   {
       /* Find pivot row */
       double maxEl = std::abs(matrix[i * N + i]);
       std::size_t maxRow = i;
       for (std::size_t k = i + 1; k < N; ++k)
           if (std::abs(matrix[k * N + i]) > maxEl) {
               maxEl = std::abs(matrix[k * N + i]);
               maxRow = k;
           }

       /* Swap rows if necessary – column wise */
       if (maxRow != i) {
           for (std::size_t k = i; k < N; ++k) {
               std::swap(matrix[maxRow * N + k],
                         matrix[i * N + k]);
           }
           std::swap(rhs[maxRow], rhs[i]);
       }

       /* Eliminate below */
       for (std::size_t k = i + 1; k < N; ++k)
       {
           double c = -matrix[k * N + i] / matrix[i * N + i];
           /* Parallelise this inner loop – it has no inter‑iteration
            * dependencies.  The number of threads is controlled by the
            * OpenMP environment variable OMP_NUM_THREADS. */
           #pragma omp simd
           for (std::size_t j = i; j < N; ++j)
           {
               if (i == j)
                   matrix[k * N + j] = 0.0;
               else
                   matrix[k * N + j] += c * matrix[i * N + j];
           }
           rhs[k] += c * rhs[i];
       }
   }

   /* 4. Back substitution */
   for (int i = static_cast<int>(N) - 1; i >= 0; --i)
   {
       x[i] = rhs[i] / matrix[i * N + i];
       for (int k = i - 1; k >= 0; --k)
           rhs[k] -= matrix[k * N + i] * x[i];
   }
}
