#pragma once
#include <vector>
#include <cmath>
#include <complex>
#include <cstdint>
#include <omp.h>

/* Fast Fourier Transform (radix‑2 decimation‑in‑time) 
 * in place using iterative butterfly operations.
 *
 * Arguments
 * ---------
 *  x : input vector of complex<double> (length must be power of two)
 *  r : output vector containing real parts (must be pre‑allocated)
 *  i : output vector containing imaginary parts (must be pre‑allocated)
 *
 * The function preserves the exact functional behaviour of the
 * reference implementation: complex data are processed, the result
 * is bit‑reversed, and the real/imaginary parts are written to the
 * provided containers.
 */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double>& r, std::vector<double>& i)
{
    const size_t N = x.size();
    if (N == 0) return;          // nothing to do
    // Allocate temporary buffers
    std::vector<std::complex<double>> a(N);
    std::vector<std::complex<double>> twiddles(N / 2);

    // Copy input
    std::copy(x.begin(), x.end(), a.begin());

    /* --- 1. Pre‑compute twiddle factors  -------------------------------- */
    const double pi = 3.1415926535897932384626433832795;
    double ang = -pi / (N / 2);
    twiddles[0] = {1.0, 0.0};
    for (size_t k = 1; k < N / 2; ++k) {
        // Recursive computation of exp(-i*ang*k)
        double w_real = std::cos(ang * k);
        double w_imag = std::sin(ang * k);
        twiddles[k] = {w_real, w_imag};
    }

    /* --- 2. In‑place radix‑2 decimation‑in‑time FFT --------------------- */
    for (size_t sz = 2; sz <= N; sz <<= 1) {
        size_t half = sz >> 1;
        size_t step = N >> sz;          // 2π/N * half
        #pragma omp parallel for schedule(static)
        for (size_t i0 = 0; i0 < N; i0 += sz) {
            for (size_t j = 0; j < half; ++j) {
                size_t idx1 = i0 + j;
                size_t idx2 = i0 + j + half;
                const std::complex<double>& t = a[idx1];
                const std::complex<double>& u = a[idx2];
                std::complex<double> w = twiddles[j * step];
                std::complex<double> tmp = u * w;
                a[idx1] = t + tmp;
                a[idx2] = t - tmp;
            }
        }
    }

    /* --- 3. Bit‑reversal permutation ------------------------------------- */
    size_t m = 0;
    for (size_t tmp = N; tmp > 1; tmp >>= 1) ++m;

    for (size_t j = 0; j < N; ++j) {
        size_t rev = __builtin_bswap32(static_cast<uint32_t>(j)) >> (32 - m);
        if (rev > j) std::swap(a[j], a[rev]);
    }

    /* --- 4. Separate real/imaginary parts -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
