#include <omp.h>

#if !defined(M_PI)
#   define M_PI 3.14159265358979323846
#endif

// ------------------------------------------------------------
// In‑place Cooley–Tukey FFT (iterative radix‑2, complex<double>)
// ------------------------------------------------------------
static inline void fft_impl(std::vector<std::complex<double>>& data)
{
    const std::size_t N = data.size();
    if (N <= 1) return;

    // ---------- bit‑reversal ----------
    std::size_t j = 0;
    for (std::size_t i = 1; i < N; ++i)
    {
        std::size_t bit = N >> 1;
        while (j & bit)
        {
            j ^= bit;
            bit >>= 1;
        }
        j ^= bit;
        if (i < j)
            std::swap(data[i], data[j]);
    }

    // ---------- iterative butterflies ----------
    for (std::size_t m = 2; m <= N; m <<= 1)
    {
        const double theta = -2.0 * M_PI / static_cast<double>(m);
        const std::complex<double> wm(std::cos(theta), std::sin(theta));

        // Parallelise the outer loop over sub‑transform start positions
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m)
        {
            std::complex<double> w(1.0, 0.0);
            for (std::size_t j = 0; j < m / 2; ++j)
            {
                const std::size_t a = k + j;
                const std::size_t b = a + m / 2;

                const std::complex<double> t = w * data[b];
                data[b] = data[a] - t;
                data[a] += t;

                w *= wm;
            }
        }
    }
}

// ------------------------------------------------------------
// Public interface (keeps original behaviour)
// ------------------------------------------------------------
inline void fft(const std::vector<std::complex<double>>& x,
                std::vector<std::complex<double>>& output)
{
    output = x;                 // Make a copy – function is *not* in‑place
    fft_impl(output);           // Compute FFT in-place on the copy
}
