#pragma once
#include <vector>
#include <algorithm>

struct Point {
    double x, y;
    bool operator<(const Point& other) const {
        return x < other.x || (x == other.x && y < other.y);
    }
};

/* Computes the convex hull of <points> and places the result into <hull>.
 * The algorithm is the classic Graham scan / Andrew monotone chain.
 */
inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {  // trivial case: hull is the original set
        hull.assign(points.begin(), points.end());
        return;
    }

    std::vector<Point> pts = points;               // make a copy for sorting
    std::sort(pts.begin(), pts.end());             // use operator<

    // Pre‑allocate maximum possible hull size (2n)
    std::vector<Point> tmp;
    tmp.reserve(2 * n);
    std::size_t k = 0;

    /* lower hull */
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(tmp[k - 2], tmp[k - 1], pts[i]) <= 0) {
            tmp.pop_back();
            --k;
        }
        tmp.push_back(pts[i]);
        ++k;
    }

    /* upper hull */
    for (std::size_t i = n - 1; i > 0; --i) {
        while (k >= 2 && cross(tmp[k - 2], tmp[k - 1], pts[i - 1]) <= 0) {
            tmp.pop_back();
            --k;
        }
        tmp.push_back(pts[i - 1]);
        ++k;
    }

    tmp.pop_back();                  // remove duplicate of first point
    hull.assign(tmp.begin(), tmp.end());  // final hull
}
