    {
        double dx = a.x - b.x;
        double dy = a.y - b.y;
        return dx * dx + dy * dy;
    }

    /* Find the closest pair distance in a rectangle */
    double closestRec(std::vector<Point>& pts, int left, int right)
    {
        int n = right - left;
        if (n <= 3)
        {
            double d = std::numeric_limits<double>::max();
            for (int i = left; i < right; ++i)
                for (int j = i + 1; j < right; ++j)
                    d = std::min(d, distSq(pts[i], pts[j]));
            std::sort(pts.begin() + left, pts.begin() + right,
                      [](const Point& a, const Point& b) { return a.y < b.y; });
            return d;
        }

        int mid = left + n / 2;
        double midX = pts[mid].x;

        double dLeft  = closestRec(pts, left,   mid);
        double dRight = closestRec(pts, mid,    right);
        double d = std::min(dLeft, dRight);

        /* Build strip */
        std::vector<Point> strip;
        strip.reserve(n);
        for (int i = left; i < right; ++i)
            if (std::abs(pts[i].x - midX) < d)
                strip.push_back(pts[i]);

        /* Sort strip by Y (already sorted by Y in recursive calls,
