        /* Check strip */
        size_t sz = strip.size();
        for (size_t i = 0; i < sz; ++i)
            for (size_t j = i + 1; j < sz && (strip[j].y - strip[i].y) < d; ++j)
                d = std::min(d, distSq(strip[i], strip[j]));

        return d;
    }
}

