#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/*
   Compute the prefix sum (inclusive scan) of the vector x into output.
   The algorithm parallelises the work across the available OpenMP
   threads and preserves the exact behaviour of std::inclusive_scan.
   Input and output sizes are assumed to be equal.
*/
void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    const size_t n = x.size();
    output.resize(n);

    const int num_threads = omp_get_max_threads();
    std::vector<int64_t> blockSum(num_threads, 0);

    // First pass: each thread computes a local prefix inside its block.
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t start = tid * n / num_threads;
        const size_t end   = (tid + 1) * n / num_threads;

        int64_t s = 0;
        for (size_t i = start; i < end; ++i) {
            s += x[i];
            output[i] = s;
        }
        blockSum[tid] = s;
    }

    // Compute the running sum of the block sums.
    std::vector<int64_t> prefixBlock(num_threads, 0);
    int64_t acc = 0;
    for (int i = 0; i < num_threads; ++i) {
        acc += blockSum[i];
        prefixBlock[i] = acc;
    }

    // Second pass: add the appropriate block offset to each block
    // (except for the first block, which is already correct).
    #pragma omp parallel for schedule(static)
    for (int tid = 1; tid < num_threads; ++tid) {
        const size_t start = tid * n / num_threads;
        const size_t end   = (tid + 1) * n / num_threads;
        const int64_t add  = prefixBlock[tid - 1];

        for (size_t i = start; i < end; ++i) {
            output[i] += add;
        }
    }
}
