#pragma once
#include <vector>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
   Matrices are stored in row-major order.
   The implementation uses blocking for cache friendliness, loop‑unrolling,
   and OpenMP to parallelise the outermost loop.
*/
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // block sizes tuned for an 8‑core x86 with L2 cache ~256 KB per core
    constexpr size_t BLOCK_M = 64;
    constexpr size_t BLOCK_K = 64;
    constexpr size_t BLOCK_N = 64;

    // parallelise over rows of A / C
    #pragma omp parallel for schedule(static)
    for (size_t i0 = 0; i0 < M; i0 += BLOCK_M) {
        size_t i_max = std::min(i0 + BLOCK_M, M);
        for (size_t k0 = 0; k0 < K; k0 += BLOCK_K) {
            size_t k_max = std::min(k0 + BLOCK_K, K);
            for (size_t j0 = 0; j0 < N; j0 += BLOCK_N) {
                size_t j_max = std::min(j0 + BLOCK_N, N);

                for (size_t i = i0; i < i_max; ++i) {
                    double* c_row = &C[i * N];
                    const double* a_row = &A[i * K];
                    for (size_t k = k0; k < k_max; ++k) {
                        double a_val = a_row[k];
                        const double* b_col = &B[k * N];
                        size_t j = j0;
                        // unroll inner j‑loop by 4
                        for (; j + 3 < j_max; j += 4) {
                            c_row[j]   += a_val * b_col[j];
                            c_row[j+1] += a_val * b_col[j+1];
                            c_row[j+2] += a_val * b_col[j+2];
                            c_row[j+3] += a_val * b_col[j+3];
                        }
                        for (; j < j_max; ++j) {
                            c_row[j] += a_val * b_col[j];
                        }
                    }
                }
            }
        }
    }
}
