/*
 * Count the number of Cartesian points in each quadrant.
 * The vector `points` contains a list of `Point` objects.
 * Store the counts in `bins`.
 *
 * Example:
 * input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
 *         {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
 * output: [3, 1, 0, 2]
 */
void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins)
{
    // Initial clearing of the output array.
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Parallel loop – each thread keeps a private set of counters.
#pragma omp parallel
    {
        std::size_t local[4] = {0, 0, 0, 0};

#pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < points.size(); ++idx) {
            const auto &p = points[idx];
            // Branch‑dispatched counting – keeps the logic identical to the
            // original implementation but removes the outer shape‑exploration.
            if (p.x >= 0.0) {
                if (p.y >= 0.0) {
                    ++local[0];      // Quadrant I
                } else {
                    ++local[3];      // Quadrant IV
                }
            } else {
                if (p.y >= 0.0) {
                    ++local[1];      // Quadrant II
                } else {
                    ++local[2];      // Quadrant III
                }
            }
        }

        // Merge local counts into the global bins array atomically.
#pragma omp critical
        {
            for (int i = 0; i < 4; ++i) {
                bins[i] += local[i];
            }
        }
    }
}
