/// Return the index of the first even integer in *x*.
/// If *x* contains no even integers, the function returns *x.size()*.
/// The implementation favours speed on modern x86‑64 CPUs, using
/// a single pass with a very small inner test.
inline std::size_t findFirstEven(std::vector<int> const& x) noexcept
{
    // Traverse the vector using a raw pointer for better cache utilisation
    // and a little faster loop control than a range based loop.
    const int* p  = x.data();
    const int* end = p + x.size();

    for (const int* q = p; q < end; ++q)
    {
        // A number is even iff its least‑significant bit is 0.
        // The bit‑wise test is usually cheaper than a division‑by‑modulus.
        if ((*q & 1) == 0)
            return static_cast<std::size_t>(q - p);
    }

    // No even integer was found – return the vector's size as prescribed.
    return x.size();
}
