namespace detail {

// Helper to sort in parallel using merge‑sort.
inline void parallelMergeSort(std::vector<Result>& data,
                              std::vector<Result>& aux,
                              size_t left, size_t right,
                              size_t threshold = 4096)
{
    if (right - left <= threshold) {
        std::sort(data.begin() + left, data.begin() + right,
                  [](const Result& a, const Result& b) {
                      return a.startTime < b.startTime;
                  });
        return;
    }

    size_t mid = (left + right) / 2;

    // Sort each half in parallel
    #pragma omp task shared(data, aux)
    parallelMergeSort(data, aux, left, mid, threshold);
    #pragma omp task shared(data, aux)
    parallelMergeSort(data, aux, mid, right, threshold);

    #pragma omp taskwait

    // Merge the two halves
    size_t i = left, j = mid, k = left;
    while (i < mid && j < right) {
        if (data[i].startTime <= data[j].startTime) {
            aux[k++] = data[i++];
        } else {
            aux[k++] = data[j++];
        }
    }
    while (i < mid) aux[k++] = data[i++];
    while (j < right) aux[k++] = data[j++];

    // Copy back
    for (size_t idx = left; idx < right; ++idx)
        data[idx] = aux[idx];
}

} // namespace detail

// Public API
inline void sortByStartTime(std::vector<Result>& results) {
    if (results.empty()) return;

    std::vector<Result> aux = results; // temporary buffer
    #pragma omp parallel
    {
        #pragma omp single
        detail::parallelMergeSort(results, aux, 0, results.size());
