/*
 * For each value in the vector `x` compute its index in the sorted vector.
 * The results are stored in `ranks_`.
 *
 * Example:
 *   input : [3.1, 2.8, 9.1, 0.4, 3.14]
 *   output: [2, 1, 4, 0, 3]
 *
 * The function uses a stable sort so that equal elements retain their
 * original ordering.
 */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    // Prepare a vector of indices 0..x.size()-1
    std::vector<size_t> indices(x.size());
    std::iota(indices.begin(), indices.end(), 0);

    // Stable sort the indices according to the values in `x`
    std::stable_sort(indices.begin(), indices.end(),
                     [&x](size_t i1, size_t i2) { return x[i1] < x[i2]; });

    // Translate sorted indices into ranks
    for (size_t i = 0; i < indices.size(); ++i) {
        ranks_[indices[i]] = i;
    }
}
