#pragma once
#include <vector>
#include <cstddef>
#include <xmmintrin.h>   // SSE (float 32-bit). For double use <emmintrin.h>
#include <immintrin.h>   // AVX

// Perform LU factorization in place, preserving exact semantics of the reference code.
// Uses AVX vectorisation and some compiler hints for speed on x86‑64 (gcc ‑O2, OpenMP).
inline void luFactorize(std::vector<double>& A, std::size_t N) {
    // Use a pointer to the underlying array for faster accesses.
    double* restrict a = A.data();

    // Outer loop: pivot row k.
    for (std::size_t k = 0; k < N; ++k) {
        double* const row_k = &a[k * N];            // pointer to the current pivot row
        const double pivot = *row_k;                // A[k][k]
        const double inv_pivot = 1.0 / pivot;       // pre‑compute reciprocal

        // Inner loop: rows below the pivot.
        for (std::size_t i = k + 1; i < N; ++i) {
            double* const row_i = &a[i * N];        // pointer to row i
            const double factor = row_i[k] * inv_pivot;
            row_i[k] = factor;                      // store L[i][k]

            // Update the remaining columns [k+1 .. N-1].
            std::size_t j = k + 1;
            const std::size_t avx_width = 4;        // AVX processes 4 doubles simultaneously
            const std::size_t vec_end = N - (N - j) % avx_width;

            // Vectorised update.
            for (; j <= vec_end - avx_width; j += avx_width) {
                // Load 4 elements of the current row.
                __m256d v_row = _mm256_loadu_pd(&row_i[j]);
                // Load 4 elements of the pivot row.
                __m256d v_piv = _mm256_loadu_pd(&row_k[j]);
                // Broadcast the factor to all lanes.
                __m256d v_fac = _mm256_set1_pd(factor);
                // Subtract factor * pivot row.
                v_row = _mm256_sub_pd(v_row, _mm256_mul_pd(v_fac, v_piv));
                // Store the result back.
                _mm256_storeu_pd(&row_i[j], v_row);
            }

            // Scalar tail for the remaining columns.
            for (; j < N; ++j) {
                row_i[j] -= factor * row_k[j];
            }
        }
    }
}
