#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <cstddef>
#include <omp.h>

#if !defined(M_PI)
#   define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// Fast Fourier Transform (in‑place)
// -----------------------------------------------------------------------------
static inline void fft_helper(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    // ---- Radix‑2 iterative FFT -------------------------------------------------
    // Upper‑triangular butterfly
    std::size_t k = N >> 1;
    std::complex<double> w = std::exp(std::complex<double>(0.0, -M_PI / static_cast<double>(N)));

    for (std::size_t n = N; n > 1; n >>= 1)
    {
        std::complex<double>  w_n = w * w;           // square twiddle
        std::complex<double>  t   = 1.0;             // running twiddle

        for (std::size_t l = 0; l < k; ++l)
        {
            for (std::size_t a = l; a < N; a += n)
            {
                std::size_t b = a + k;
                std::complex<double> tmp = x[a] - x[b];
                x[a] += x[b];
                x[b]  = tmp * t;
            }
            t *= w_n;
        }
        w = w_n;
        k >>= 1;
    }

    // ---- Bit reversal ----------------------------------------------------------
    const std::size_t m = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    for (std::size_t a = 0; a < N; ++a)
    {
        std::size_t b = a;
        b = ((b >> 1) & 0x55555555) | ((b << 1) & 0xaaaaaaaa);
        b = ((b >> 2) & 0x33333333) | ((b << 2) & 0xcccccccc);
        b = ((b >> 4) & 0x0f0f0f0f) | ((b << 4) & 0xf0f0f0f0);
        b = ((b >> 8) & 0x00ff00ff) | ((b << 8) & 0xff00ff00);
        b = (b >> 16) | (b << 16);
        b >>= (32 - m);

        if (b > a)
        {
            std::swap(x[a], x[b]);
        }
    }
}

// -----------------------------------------------------------------------------
// Inverse FFT (in‑place)
// -----------------------------------------------------------------------------
static inline void ifft(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // 1. conjugate
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[i] = std::conj(x[i]);

    // 2. forward FFT
    fft_helper(x);

    // 3. conjugate again
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[i] = std::conj(x[i]);

    // 4. scale by 1/N
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(N); ++i)
        x[i] *= invN;
}
