#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

/*
 * Sort the vector `x` of complex numbers by their magnitude in ascending order.
 * The original behavior is preserved (exact ordering for equal magnitudes).
 *
 * Optimizations:
 *   - Avoid the costly `std::abs` by comparing squared magnitudes.
 *   - Compute the squared magnitudes in parallel using OpenMP.
 *   - Perform a two‑step sort: first create an auxiliary index array,
 *     then sort indices with the comparator, and finally reorder `x`.
 */
inline void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    const std::size_t n = x.size();
    if (n <= 1) return;

    // Parallel computation of squared magnitudes.
    std::vector<double> mag2(n);
#pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        const double re = x[i].real();
        const double im = x[i].imag();
        mag2[i] = re*re + im*im;          // |z|^2
    }

    // Create indices and perform a stable sort so original relative order
    // of equal magnitudes is preserved (exactly as std::sort would).
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    std::stable_sort(idx.begin(), idx.end(),
        [&mag2](std::size_t a, std::size_t b) noexcept {
            return mag2[a] < mag2[b];
        });

    // Reorder the original vector according to sorted indices.
    std::vector<std::complex<double>> tmp;
    tmp.reserve(n);
    for (const std::size_t i : idx)
        tmp.push_back(x[i]);

    x.swap(tmp);
}
