//===-- jacobi2d_opt.cpp ---------------------------------------*- C++ -*-===//
//
//  High‑performance implementation of a 5‑point 2‑D Jacobi stencil
//
//  The function keeps the exact semantics of the original code but
//  exploits cache locality, pointer arithmetic and OpenMP parallelism.
//  Written for GCC ≥ 5 with OpenMP support.
//
//==============================================================================

#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

// Helper to expose a raw pointer to the underlying data.
inline double const* data(const std::vector<double>& v) { return v.data(); }
inline double*       data(std::vector<double>& v)       { return v.data(); }

/*
 * Compute one iteration of a 5‑point 2‑D Jacobi stencil on `input`.
 * The result is written into `output`.
 * Each cell is updated as the average of itself and its four orthogonal
 * neighbours. Out‑of‑bounds neighbours contribute 0.
 *
 * Parameters
 * ----------
 * input  : `NxN` grid stored in row‑major order.
 * output : same shape as `input`. Will be overwritten.
 * N      : the grid dimension.
 *
 * Example
 * -------
 * input  : [[3, 4, 1],
 *           [0, 1, 7],
 *           [5, 3, 2]]
 * output : [[1.4, 1.8, 2.4],
 *           [1.8, 3.0, 2.2],
 *           [1.6, 2.2, 2.4]]
 */
inline void jacobi2D(const std::vector<double>& input,
                     std::vector<double>&       output,
                     std::size_t                N)
{
    const double inv5 = 0.2;          // 1/5
    const double*  in  = data(input);
    double*        out = data(output);

    // Parallelize the two nested loops with static scheduling.
    // The iteration count is small enough that a single outer
    // loop is sufficient; the inner loop is kept for readability
    // and to keep the compiler able to auto‑vectorise.
    #pragma omp parallel for schedule(static) collapse(2) \
                 firstprivate(in, out, N, inv5)
    for (std::size_t i = 0; i < N; ++i)
    {
        const std::size_t iN  = i * N;
        const std::size_t im1N = (i > 0)   ? (i-1) * N : N;   // unused, dummy
        const std::size_t ip1N = (i + 1 < N) ? (i+1) * N : 0; // unused, dummy

        for (std::size_t j = 0; j < N; ++j)
        {
            double sum = in[iN + j];          // center

            if (i > 0)       sum += in[im1N + j];     // north
            if (i + 1 < N)   sum += in[ip1N + j];     // south
            if (j > 0)       sum += in[iN + (j-1)];   // west
            if (j + 1 < N)   sum += in[iN + (j+1)];   // east

            out[iN + j] = sum * inv5;
        }
    }
}
