/// Computes the reverse prefix sum of the vector `x` into `output`.
/// For each index i, `output[i]` is the sum of the last (i+1) elements of `x`.
/// Example:
///   x = [1, 7, 4, 6, 6, 2]   →  output = [2, 8, 14, 18, 25, 26]
///   x = [3, 3, 7, 1, -2]      →  output = [-2, -1, 6, 9, 12]
inline void reversePrefixSum(const std::vector<int>& x, std::vector<int>& output) {
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    int sum = 0;
    // Compute sums of suffixes and place them in reverse order.
    for (std::size_t i = n; i-- > 0;) {   // i goes from n-1 to 0
        sum += x[i];
        output[n - 1 - i] = sum;          // output[0] gets x[n-1], etc.
    }
}
