size_t findClosestToPi(std::vector<double> const& x) {
    /* Fast linear scan with OpenMP parallel reduction.
       Keeps the original semantics while making full use of 8 threads. */
    constexpr double PI = std::numbers::pi;          // use C++20 constant
    const size_t n = x.size();
    if (n == 0) return 0;                            // guard against empty input

    // Thread‑local minima
    std::vector<double> min_diffs(std::thread::hardware_concurrency(), std::numeric_limits<double>::infinity());
    std::vector<size_t> min_idx(std::thread::hardware_concurrency(), 0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        double local_min = std::numeric_limits<double>::infinity();
        size_t local_idx = 0;

        #pragma omp for schedule(static)
        for (size_t i = 0; i < n; ++i) {
            const double diff = std::abs(x[i] - PI);
            if (diff < local_min) {
                local_min = diff;
                local_idx = i;
            }
        }

        min_diffs[tid] = local_min;
        min_idx[tid]   = local_idx;
    }

    // combine thread results
    size_t best_idx = 0;
    double best_diff = min_diffs[0];
    for (size_t t = 1; t < min_diffs.size(); ++t) {
        if (min_diffs[t] < best_diff) {
            best_diff = min_diffs[t];
            best_idx = min_idx[t];
        }
    }
    return best_idx;
}
