#pragma once
#include <vector>
#include <omp.h>
#include <cstddef>

/*
 * Gaussian elimination (forward elimination + back substitution) with
 * a simple check for zero pivots. The implementation is fully
 * cache‑friendly: we use raw pointers to the underlying storage
 * of the std::vector objects and parallelise the row elimination
 * stage with OpenMP.
 *
 * This implementation keeps the exact observable behaviour of the
 * original algorithm (return on a zero pivot, no partial pivoting,
 * the same numerical order). Only performance‑related changes are
 * made: data layout (row‑major), no temporary copies beyond the
 * ones required by the API, and OpenMP parallelisation of the
 * inner loops.
 *
 * Note: reduce the compiler flags to `-O2 -fopenmp` as requested.
 */

void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Work copies (original matrices must not be modified)
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double *a = A_copy.data();           // row‑major access
    double *b_c = b_copy.data();

    // Forward elimination
    for (size_t i = 0; i + 1 < N; ++i) {
        double pivot = a[i * N + i];
        if (pivot == 0.0)                // cannot continue, return 0
            return;

        // Parallelise elimination of rows below the pivot
        #pragma omp parallel for schedule(static)
        for (int j = int(i) + 1; j < int(N); ++j) {
            double factor = a[j * N + i] / pivot;
            double *row_j = a + j * N;
            double *row_i = a + i * N;

            // Update the remaining elements of the row
            #pragma omp simd
            for (size_t k = i; k < N; ++k)
                row_j[k] -= factor * row_i[k];

            b_c[j] -= factor * b_c[i];
        }
    }

    // Back substitution (not parallelised – it is inherently serial)
    for (int i = int(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double *row_i = a + i * N;
        for (size_t j = size_t(i) + 1; j < N; ++j)
            sum += row_i[j] * x[j];
        x[i] = (b_c[i] - sum) / a[i * N + i];
    }
}
