#include <atomic>
#include <omp.h>

/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   Examples:
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=7
   output: true
   input: x=[1,8,4,3,2], y=[3,4,4,1,1,7], val=1
   output: false
*/
bool xorContains(const std::vector<int>& x, const std::vector<int>& y, int val) {
    // Fast paths for empty vectors
    if (x.empty() && y.empty()) return false;
    if (x.empty())  return std::any_of(y.begin(), y.end(), [&](int v){ return v==val; }) == true ? false : true;
    if (y.empty())  return std::any_of(x.begin(), x.end(), [&](int v){ return v==val; }) == true ? false : true;

    // Flags that will hold whether val was found in each vector.
    std::atomic<bool> foundInX(false);
    std::atomic<bool> foundInY(false);

    // Parallel search: one section for each vector.
    #pragma omp parallel sections
    {
        #pragma omp section
        {
            for (size_t i = 0; i < x.size(); ++i) {
                if (x[i] == val) { foundInX.store(true, std::memory_order_relaxed); break; }
            }
        }

        #pragma omp section
        {
            for (size_t i = 0; i < y.size(); ++i) {
                if (y[i] == val) { foundInY.store(true, std::memory_order_relaxed); break; }
            }
        }
    }

    // XOR the two results.
    return (foundInX.load(std::memory_order_relaxed) !=
            foundInY.load(std::memory_order_relaxed));
}
