```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <omp.h>

struct Point
{
    double x, y;
};

//-------------------------------------------------------------------------
// Utility helpers – defined as inline for zero‑overhead.
//
// 1. Cross product of OA × OB – positive for counter‑clockwise turn.
// 2. Euclidean distance; uses only one sqrt per pair by pre‑calculating
//    the squared difference. The function is tiny enough that the
//    compiler will inline it automatically.
//
static inline double cross(const Point& a, const Point& b, const Point& c) noexcept
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

static inline double distance(const Point& a, const Point& b) noexcept
{
    double dx = a.x - b.x, dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}
// -------------------------------------------------------------------------

// Perimeter of the convex hull – O(n log n) time, O(n) memory
//
// 1.  Sort points lexicographically (x, then y).  The sorting is
//     performed once – sorting cannot be parallelised safely without
//     carrying a comparator that still needs to be thread‑safe,
//     but the cost is O(n log n) and much smaller than the main
//     convex‑hull construction.
//
// 2.  Construct the lower and upper hulls using the monotone chain
//     algorithm (a.k.a. Andrew's algorithm).  The operations inside
//     the hull construction are all O(1) and, because they are
//     data‑dependent, we do not parallelise that part to guarantee
//     deterministic behaviour.
//
// 3.  Compute the perimeter in a final linear scan.  This loop is
//     embarrassingly parallel – we split the work among the available
//     threads and sum the partial results later.
//
// 4.  The final thread‑safe sum uses a critical section with no
//     significant overhead on modern CPUs with only a few threads.
//
// The function preserves the exact semantics of the original code
// – the same geometric shape and perimeter is returned for any
// allowable input.
//
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) {   // less than 3 points – no polygon can be formed
        return 0.0;
    }

    // 1. Sort points lexicographically.
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // 2. Build convex hull using the monotone chain algorithm.
    std::vector<Point> hull(2 * n);   // allocate maximal possible size
    std::size_t k = 0;                // current hull size

    // Lower hull
    for (std::size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // Upper hull
    for (std::size_t i = n; i-- > 1;)
    {
        while (k >= 2 + static_cast<std::size_t>(1) &&
               cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }

    hull.resize(k - 1);   // the last point is the same as the first

    // 3. Compute perimeter – parallelised
    const std::size_t m = hull.size();
    double perimeter = 0.0;

    #pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i < m; ++i)
    {
        const std::size_t next = (i + 1) % m;
        perimeter += distance(hull[i], hull[next]);
    }

    return perimeter;
}
